private boolean usesDataDescriptor(final int zipMethod) {
    // If we're writing to a seekable channel, we don't need a data descriptor
    if (channel != null) {
        return false;
    }
    // For non-seekable channels, we normally need a data descriptor for DEFLATED entries
    // However, if we already have the CRC, compressed size, and size known in advance,
    // we don't need the data descriptor
    if (zipMethod == DEFLATED && entry != null) {
        ZipArchiveEntry currentEntry = entry.entry;
        boolean hasCrc = currentEntry.getCrc() != ZipArchiveEntry.CRC_UNKNOWN;
        boolean hasSize = currentEntry.getSize() != ArchiveEntry.SIZE_UNKNOWN;
        boolean hasCompressedSize = currentEntry.getCompressedSize() != ArchiveEntry.SIZE_UNKNOWN;

        // If all three values are known, we don't need a data descriptor
        if (hasCrc && hasSize && hasCompressedSize) {
            return false;
        }
    }
    return zipMethod == DEFLATED && channel == null;
}

